import React, { useState, useEffect } from 'react';
import { db } from '../../utils/firebase';
import { doc, getDoc, onSnapshot, collection, getDocs, addDoc, deleteDoc, query, where } from 'firebase/firestore';
import { ArrowUpRight, ArrowDownLeft, Calendar, User, Layers, AlertCircle, Shield, Trash2, PlusCircle, MapPin } from 'lucide-react';

export default function MaterialDept() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [adminId, setAdminId] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  // DYNAMIC STATES
  const [assignedArea, setAssignedArea] = useState(''); 
  const [logisticsSector, setLogisticsSector] = useState('');
  const [workersList, setWorkersList] = useState([]);
  const [transactionLogs, setTransactionLogs] = useState([]);
  const [isLoadingLogs, setIsLoadingLogs] = useState(false);

  // Form States
  const [workerName, setWorkerName] = useState('');
  const [workerLogin, setWorkerLogin] = useState('');
  const [workerPassword, setWorkerPassword] = useState('');
  const [isAddingWorker, setIsAddingWorker] = useState(false);

  // 1. AUTH GATE - DYNAMICALLY SETS AREA FROM FIREBASE
  const handleAdminAuthGate = async (e) => {
    e.preventDefault();
    setAuthError(null);
    setIsAuthenticating(true);

    try {
      const vendorRef = doc(db, "vendors", adminId.trim());
      const snap = await getDoc(vendorRef);

      if (snap.exists()) {
        const data = snap.data();
        if (String(data.password) === String(password)) {
          // Yahan se assign hota hai area dynamic taur par
          setAssignedArea(data.targetArea || 'Unassigned');
          setLogisticsSector(data.logisticsSectorType || 'General');
          setIsAuthenticated(true);
        } else {
          setAuthError("Incorrect password.");
        }
      } else {
        setAuthError("Vendor ID not found.");
      }
    } catch (err) {
      setAuthError("System error: " + err.message);
    } finally {
      setIsAuthenticating(false);
    }
  };

  // 2. DYNAMIC LOGS & WORKERS SYNC
  useEffect(() => {
    if (!isAuthenticated || !assignedArea || assignedArea === 'Unassigned') return;

    // Load Workers
    const syncWorkers = async () => {
      const colRef = collection(db, "vendors", assignedArea.trim(), "workers");
      const snap = await getDocs(colRef);
      setWorkersList(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    };
    syncWorkers();

    // Load Live Logs
    const registryRef = doc(db, "registry", assignedArea.trim());
    const unsub = onSnapshot(registryRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data();
        setTransactionLogs(data.auditLogs ? [...data.auditLogs].reverse() : []);
      }
      setIsLoadingLogs(false);
    });

    return () => unsub();
  }, [isAuthenticated, assignedArea]);

  // UI STYLES
  const styles = {
    layout: { padding: '24px', backgroundColor: '#F8FAFC', minHeight: '100vh', fontFamily: 'sans-serif' },
    authWrapper: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#0B1220' },
    authCard: { backgroundColor: '#FFFFFF', padding: '35px', borderRadius: '12px', width: '400px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' },
    metaHeader: { display: 'flex', justifyContent: 'space-between', backgroundColor: '#0F172A', padding: '20px', borderRadius: '12px', color: '#FFFFFF', marginBottom: '20px' },
    card: { backgroundColor: '#fff', padding: '24px', borderRadius: '12px', border: '1px solid #E2E8F0', marginBottom: '20px' },
    input: { padding: '10px 14px', border: '1px solid #CBD5E1', borderRadius: '8px', width: '100%', marginBottom: '10px' },
    button: { padding: '10px 20px', backgroundColor: '#10B981', color: '#FFFFFF', border: 'none', borderRadius: '8px', cursor: 'pointer', width: '100%' }
  };

  if (!isAuthenticated) {
    return (
      <div style={styles.authWrapper}>
        <div style={styles.authCard}>
          <h2 style={{ textAlign: 'center' }}>Material Storage Login</h2>
          {authError && <p style={{ color: 'red', fontSize: '12px' }}>{authError}</p>}
          <form onSubmit={handleAdminAuthGate}>
            <input style={styles.input} placeholder="Admin ID" onChange={(e) => setAdminId(e.target.value)} />
            <input style={styles.input} type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} />
            <button style={styles.button} type="submit" disabled={isAuthenticating}>
              {isAuthenticating ? "Verifying..." : "Unlock"}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.layout}>
      <div style={styles.metaHeader}>
        <h1>Material Dept Management</h1>
        <div style={{ display: 'flex', gap: '15px' }}>
          <div><MapPin size={16} /> Area: <b>{assignedArea}</b></div>
          <div><Shield size={16} /> Sector: <b>{logisticsSector}</b></div>
        </div>
      </div>

      <div style={styles.card}>
        <h3>Register Operator at [{assignedArea}]</h3>
        <input style={styles.input} placeholder="Name" onChange={(e) => setWorkerName(e.target.value)} />
        <input style={styles.input} placeholder="Login ID" onChange={(e) => setWorkerLogin(e.target.value)} />
        <input style={styles.input} type="password" placeholder="Password" onChange={(e) => setWorkerPassword(e.target.value)} />
        <button style={styles.button} onClick={async () => {
          await addDoc(collection(db, "vendors", assignedArea.trim(), "workers"), { workerName, loginId: workerLogin, password: workerPassword });
          window.location.reload();
        }}>Add Operator</button>
      </div>

      {/* List */}
      <div style={styles.card}>
        <h3>Active Operators</h3>
        {workersList.map(w => <div key={w.id}>{w.workerName}</div>)}
      </div>
    </div>
  );
}
